// Acessa o primeiro item da entrada
const input = items[0].json;

// De acordo com seu ultimo print, o caminho e content -> parts[0] -> text
const contentParts = input.content && input.content.parts;

if (!contentParts || !contentParts[0] || !contentParts[0].text) {
    return { 
        error: "Caminho do texto nao localizado na estrutura do Gemini", 
        estrutura_recebida: input 
    };
}

const rawText = contentParts[0].text;

// Remove marcadores de markdown caso existam
const cleanText = rawText.replace(/```json|```/g, "").trim();

let productsArray = [];
try {
    productsArray = JSON.parse(cleanText);
} catch (e) {
    return { 
        error: "Falha ao converter string para JSON", 
        texto_limpo: cleanText,
        erro_original: e.message 
    };
}

// Retorna os itens formatados para o n8n
return productsArray.map(product => {
    return {
        json: {
            product_name: product.product_name,
            ref_id: product.ref_id,
            price: product.price,
            box_2d: product.box_2d,
            extracted_at: new Date().toISOString()
        }
    };
});
